  (3, 'Hebrews 1:2', 6),
  (3, 'Psalm 33:6', 7),
  -- v.4 life and light
  (4, 'John 8:12', 8),
  (4, 'John 14:6', 9),
  -- v.5 light in darkness
  (5, 'John 3:19-21', 10),
  (5, 'Isaiah 9:2', 11),
  -- v.9 true light
  (9, 'John 8:12', 12),
  (9, 'John 9:5', 13),
  -- v.11 his own received him not
  (11, 'Isaiah 53:3', 14),
  (11, 'Matthew 23:37', 15),
