  (12, 'Romans 8:14-16', 16),
  (12, 'Galatians 3:26', 17),
  (12, '1 John 3:1-2', 18),
  -- v.13 born of God
  (13, 'John 3:3-8', 19),
  (13, '1 Peter 1:23', 20),
  (13, 'James 1:18', 21),
  -- v.14 Word made flesh
  (14, 'Philippians 2:6-8', 22),
  (14, '1 Timothy 3:16', 23),
  (14, 'Hebrews 2:14', 24),
  (14, 'Exodus 34:6', 25),
  (14, 'Exodus 40:34-35', 26),
  -- v.17 grace and truth
  (17, 'Romans 6:14', 27),
  (17, 'John 14:6', 28),
  -- v.18 no man hath seen God
  (18, 'Exodus 33:20', 29),
