  -- v.42 Cephas/Peter
  (42, 'Matthew 16:18', 42),
  -- v.45 Moses and prophets
  (45, 'Deuteronomy 18:15-18', 43),
  (45, 'Luke 24:27', 44),
  -- v.49 Son of God King of Israel
  (49, 'Psalm 2:7', 45),
  (49, 'Zephaniah 3:15', 46),
  -- v.51 Jacob's ladder
  (51, 'Genesis 28:12', 47),
  (51, 'Daniel 7:13-14', 48)
) AS cr(verse_number, reference, ref_order)
WHERE b.name = 'John' AND c.chapter_number = 1
  AND v.verse_number = cr.verse_number;

-- JOHN CHAPTER 1 — BACKFILL (additional word_studies + cross_references)

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἐν ἀρχῇ', 'en archē', 'G1722/G746', 'In the beginning — deliberate echo of Genesis 1:1 LXX (en archē epoiēsen ho theos); the new creation begins where the first creation began. Archē denotes the absolute beginning, before time and creation.', 100),
  (1, 'πρὸς τὸν θεόν', 'pros ton theon', 'G4314/G2316', 'With/toward God — pros + accusative implies face-to-face relation, not mere proximity; eternal communion of distinct persons. Not en (in) but pros: relational orientation.', 101),
  (1, 'θεὸς ἦν ὁ λόγος', 'theos ēn ho logos', 'G2316/G2258/G3056', 'The Word was God — anarthrous theos (no article) emphasizes qualitative deity, not numerical identity; "what God was, the Word was" (Colwell''s rule). Refutes Arianism.', 102),
  (3, 'ἐγένετο', 'egeneto', 'G1096', 'Came into being (aorist) — used 3 times in v.3 to underline that all created things owe their existence to the Word. Contrasts with ēn ("was") in vv.1-2 of the eternal Word.', 103),
  (5, 'φαίνει', 'phainei', 'G5316', 'Shines (present) — continuous, undefeated illumination; the light has been and continues to be shining in the darkness.', 104),
  (5, 'κατέλαβεν', 'katelaben', 'G2638', 'Overcame/comprehended — double meaning: the darkness neither understood nor mastered the light. John''s irony often exploits this ambiguity.', 105),
  (6, 'ἀπεσταλμένος', 'apestalmenos', 'G649', 'Having been sent (perfect passive of apostellō) — abiding apostleship of John the Baptist; he stands as ongoing witness.', 106),
  (7, 'εἰς μαρτυρίαν', 'eis martyrian', 'G1519/G3141', 'For witness — purpose of John''s mission; martyrian: legal-evidentiary testimony, key Johannine theme.', 107),
  (9, 'τὸ φῶς τὸ ἀληθινὸν', 'to phōs to alēthinon', 'G5457/G228', 'The true light — alēthinos: real, genuine, archetypal (vs counterfeit); Christ is the original of which all earthly light is shadow.', 108),
  (11, 'τὰ ἴδια... οἱ ἴδιοι', 'ta idia... hoi idioi', 'G2398', 'His own things... his own people — heart-breaking double idia: he came to his own creation/possession and his own covenant people did not receive him.', 109),
  (11, 'παρέλαβον', 'parelabon', 'G3880', 'Received/welcomed — formal reception; not active rejection but failure to welcome the one who had come home.', 110),
  (12, 'ἐξουσίαν', 'exousian', 'G1849', 'Right/authority — not "power" but legal right; adoption confers a right, not merely capacity. Contrast with biological begetting in v.13.', 111),
  (13, 'ἐγεννήθησαν', 'egennēthēsan', 'G1080', 'Were born (aorist passive) — divine begetting; threefold negation ("not of blood, not of will of flesh, not of will of man") emphasizes pure divine initiative.', 112),
  (14, 'ἐσκήνωσεν', 'eskēnōsen', 'G4637', 'Tabernacled/pitched his tent — skēnoō: deliberate echo of OT Tabernacle (mishkan/skēnē); divine glory dwells among us in human flesh.', 113),
  (14, 'μονογενοῦς', 'monogenous', 'G3439', 'Only-begotten/unique — monos + genos: of the only kind; emphasizes unique sonship, not biological generation.', 114),
  (14, 'πλήρης', 'plērēs', 'G4134', 'Full — full of grace and truth; Hebrew echo of Exod 34:6 ("abundant in chesed and emet") describing Yahweh on Sinai.', 115),
  (16, 'πληρώματος', 'plērōmatos', 'G4138', 'Fullness — Pauline-cosmic word (Col 1:19; 2:9); the inexhaustible reservoir of Christ.', 116),
  (16, 'χάριν ἀντὶ χάριτος', 'charin anti charitos', 'G5485/G473', 'Grace upon/in place of grace — anti: succession or replacement; either "grace heaped on grace" or "new covenant grace replacing old".', 117),
  (17, 'ἀλήθεια', 'alētheia', 'G225', 'Truth — paired with grace; Hebrew emet (faithfulness, reliability); Christ embodies covenant fidelity.', 118),
  (18, 'ἐξηγήσατο', 'exēgēsato', 'G1834', 'Explained/exegeted — from which English "exegesis"; the Son draws out and makes known the unseen Father.', 119),
  (18, 'κόλπον', 'kolpon', 'G2859', 'Bosom — intimate position of love and confidence (cf. 13:23); the Son knows the Father from inside the Father''s embrace.', 120),
  (23, 'εὐθύνατε', 'euthynate', 'G2116', 'Make straight — quotation of Isaiah 40:3 LXX; preparing the way of Yahweh implies Yahweh''s coming = Jesus''s coming.', 121),
  (29, 'αἴρων', 'airōn', 'G142', 'Taking away (present participle) — continuous removal; the Lamb both bears and removes sin permanently.', 122),
  (29, 'ἁμαρτίαν τοῦ κόσμου', 'hamartian tou kosmou', 'G266/G2889', 'Sin of the world — singular hamartia (sin as principle, not sins plural); cosmic scope of atonement.', 123),
  (32, 'περιστερὰν', 'peristeran', 'G4058', 'Dove — Spirit''s descent in dove form; possible echoes of Gen 1:2 (Spirit hovering) and Gen 8 (Noah''s dove).', 124),
  (32, 'ἔμεινεν', 'emeinen', 'G3306', 'Remained/abode — menō: key Johannine verb; Spirit''s permanent abiding marks Jesus as the Spirit-Anointed Messiah (vs OT temporary anointings).', 125),
  (33, 'βαπτίζων ἐν πνεύματι ἁγίῳ', 'baptizōn en pneumati hagiō', 'G907/G4151/G40', 'Baptizing in the Holy Spirit — the messianic gift (Joel 2:28; Acts 2); contrast with John''s preparatory water baptism.', 126),
  (34, 'υἱὸς τοῦ θεοῦ', 'huios tou theou', 'G5207/G2316', 'Son of God — John the Baptist''s climactic confession; some manuscripts read eklektos (chosen) — Servant Songs allusion.', 127),
  (38, 'ῥαββί', 'rhabbi', 'G4461', 'Rabbi — "my great one"; honorific for teachers; first disciples'' address shows respect short of full faith.', 128),
  (38, 'μένεις', 'meneis', 'G3306', 'Where do you abide? — menō again; the disciples instinctively ask the right Johannine question.', 129),
  (41, 'εὑρίσκει', 'heuriskei', 'G2147', 'Finds — Andrew''s evangelism in three steps: finds, brings, and they meet Jesus (vv.41-42).', 130),
  (41, 'Χριστός', 'Christos', 'G5547', 'Christ — Greek translation of Messiah (Anointed One); royal-priestly figure of OT prophecy.', 131),
  (42, 'Κηφᾶς', 'Kēphas', 'G2786', 'Cephas — Aramaic for "rock" (kēpha); Greek Petros; renaming signals Jesus''s sovereign reshaping of identity (cf. Abram→Abraham).', 132),
  (45, 'Ναζαρέτ', 'Nazaret', 'G3478', 'Nazareth — obscure Galilean village (~200 inhabitants in Jesus''s day); raises Nathanael''s skepticism (v.46).', 133),
  (47, 'ἀληθῶς Ἰσραηλίτης', 'alēthōs Israēlitēs', 'G230/G2475', 'Truly an Israelite — Jesus reverses the name "Jacob/Yaakov" (heel-grabber, deceiver) by negating dolos (guile).', 134),
  (47, 'δόλος', 'dolos', 'G1388', 'Guile/deceit — the very thing Jacob had until his transformation (Gen 32:28); Nathanael is a "transformed Jacob".', 135),
  (51, 'ἀναβαίνοντας καὶ καταβαίνοντας', 'anabainontas kai katabainontas', 'G305/G2597', 'Ascending and descending — Jesus is the Jacob''s Ladder (Gen 28:12); the meeting-point of heaven and earth.', 136)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'John' AND c.chapter_number = 1 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

